dtsPropsFor.Badge:
/** Tono semántico que define el color de fondo y texto. */
tono?: "neutral" | "info" | "brand" | "success" | "warning" | "danger";
className?: string;
children?: React.ReactNode;

dtsPropsFor.Button:
/** Variante de color. */
variant?: "primary" | "secondary" | "ghost" | "danger";
/** Tamaño del botón. */
size?: "sm" | "md" | "lg";
/** Icono opcional (componente lucide-react) a la izquierda del texto. */
icon?: React.ComponentType<{ size?: number }>;
/** Ocupa todo el ancho disponible. */
block?: boolean;
className?: string;
children?: React.ReactNode;
type?: "button" | "submit" | "reset";
disabled?: boolean;
onClick?: (e: React.MouseEvent<HTMLButtonElement>) => void;

dtsPropsFor.Card:
/** Título de la cabecera (opcional). */
title?: React.ReactNode;
/** Subtítulo bajo el título. */
subtitle?: React.ReactNode;
/** Nodo alineado a la derecha de la cabecera (botones, acciones). */
action?: React.ReactNode;
/** Eleva la tarjeta al pasar el cursor. */
hover?: boolean;
className?: string;
children?: React.ReactNode;

dtsPropsFor.Input:
/** Etiqueta asociada al campo (accesible vía id). */
label?: string;
/** Elemento subyacente. */
as?: "input" | "select" | "textarea";
/** Texto de ayuda bajo el campo. */
hint?: string;
/** Mensaje de error; activa el estilo de error. */
error?: string;
className?: string;
/** Opciones cuando as="select". */
children?: React.ReactNode;
placeholder?: string;
value?: string | number;
type?: string;
onChange?: (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => void;

dtsPropsFor.Logo:
/** true sobre fondos oscuros (texto claro). */
light?: boolean;
/** Muestra el texto "GeoTrack / SIOL · SAVA" junto al monograma. */
wordmark?: boolean;
className?: string;

dtsPropsFor.Modal:
/** Controla la visibilidad. */
open: boolean;
/** Se llama al pedir cierre (Escape o clic fuera). */
onClose: () => void;
/** Centrado con zoom, o panel lateral deslizante. */
variant?: "center" | "right";
className?: string;
children?: React.ReactNode;

dtsPropsFor.PageHeader:
/** Título de la página. */
titulo: string;
/** Subtítulo opcional. */
subtitulo?: string;
/** Acciones alineadas a la derecha (botones). */
children?: React.ReactNode;

dtsPropsFor.PasswordInput:
/** Etiqueta asociada al campo. */
label?: string;
/** Mensaje de error; activa el estilo de error. */
error?: string;
/** Texto de ayuda bajo el campo. */
hint?: string;
className?: string;
placeholder?: string;
value?: string;
onChange?: (e: React.ChangeEvent<HTMLInputElement>) => void;

dtsPropsFor.Skeleton:
/** Tamaño/forma vía clases Tailwind (p. ej. "h-8 w-24"). */
className?: string;
/** Clase de redondeo del borde. */
rounded?: string;

dtsPropsFor.StatCard:
/** Etiqueta superior del KPI. */
label: string;
/** Valor mostrado (los números se animan al aparecer). */
value: number | string;
/** Icono en chip (componente lucide-react). */
icon?: React.ComponentType<{ size?: number }>;
/** Tono del chip y de la barra de progreso. */
tone?: "brand" | "info" | "success" | "warning" | "danger";
/** Porcentaje 0–100; dibuja una barra de progreso real. */
progress?: number;
/** Texto bajo la barra de progreso. */
progressLabel?: string;
/** Texto de apoyo cuando no hay barra. */
hint?: string;
